import { useState } from 'react';
import { useNavigate, Link } from 'react-router-dom';
import { supabase } from '../services/supabaseClient';
import { useTheme } from '../contexts/ThemeContext';

export default function Navbar({ user, setUser }) {
  const navigate = useNavigate();
  const [showDropdown, setShowDropdown] = useState(false);
  const { theme, toggleTheme } = useTheme();

  const handleLogout = async () => {
    await supabase.auth.signOut();
    setUser(null);
    setShowDropdown(false);
  };

  const toggleDropdown = () => {
    setShowDropdown(!showDropdown);
  };

  const initials = user?.email ? user.email.charAt(0).toUpperCase() : '?';

  return (
    <div className="w-full bg-white/80 backdrop-blur-md border-b border-gray-200 px-10 py-4 flex items-center justify-between shadow-sm">
      {/* LOGO */}
      <h1 className="text-xl font-bold cursor-pointer hover:scale-105 transition-transform duration-300" onClick={() => navigate('/')}>
        Research<span className="text-teal-600 bg-gradient-to-r from-teal-500 to-blue-500 bg-clip-text text-transparent">Mate</span>
      </h1>

      {/* MENU */}
      <div className="flex gap-8 text-gray-600 font-medium">
        <Link to="/" className="relative pb-1 hover:text-black transition-colors duration-300 group">
          <span className="text-teal-600 border-b-2 border-teal-600 pb-1">Home</span>
          <span className="absolute -bottom-1 left-0 w-0 h-0.5 bg-teal-600 transition-all duration-300 group-hover:w-full"></span>
        </Link>
        <button className="hover:text-black hover-lift transition-all duration-300">
          AI Assistant
        </button>
        <button className="hover:text-black hover-lift transition-all duration-300">
          Paper Insights
        </button>
        <button className="hover:text-black hover-lift transition-all duration-300">
          Recommendations
        </button>
        <button className="hover:text-black hover-lift transition-all duration-300">
          Simplifier
        </button>
        <button className="hover:text-black hover-lift transition-all duration-300">
          Help
        </button>
      </div>

      {/* RIGHT SIDE */}
      <div className="flex items-center gap-4">
        {/* Theme Icon */}
        <button className="text-gray-500 text-lg hover:text-gray-700 hover:rotate-12 transition-all duration-300 hover-lift">
          🌙
        </button>

        {user ? (
          <div className="relative">
            <button
              onClick={toggleDropdown}
              className="w-10 h-10 bg-gradient-to-br from-teal-500 to-blue-500 text-white rounded-full flex items-center justify-center text-sm font-semibold hover:scale-110 hover:ring-4 ring-teal-200/50 transition-all duration-300 shadow-md"
              title="User menu"
            >
              {initials}
            </button>
            {showDropdown && (
              <div className="absolute right-0 mt-2 w-48 bg-white/95 backdrop-blur-sm border border-gray-200 rounded-xl shadow-2xl py-1 z-50 animate-fade-in-up">
                <Link
                  to="/profile"
                  className="block px-4 py-3 text-sm text-gray-700 hover:bg-gray-100 hover-lift rounded-lg mx-1 transition-all duration-200"
                  onClick={() => setShowDropdown(false)}
                >
                  Profile
                </Link>
                <button
                  onClick={handleLogout}
                  className="w-full text-left px-4 py-3 text-sm text-red-600 hover:bg-red-50 hover-lift rounded-lg mx-1 transition-all duration-200"
                >
                  Sign Out
                </button>
              </div>
            )}
          </div>
        ) : (
          <button
            onClick={() => navigate("/auth")}
            className="btn shadow-lg hover:shadow-xl bg-gradient-to-r from-teal-500 to-teal-600 hover:from-teal-600 hover:to-teal-700"
          >
            Sign In
          </button>
        )}
      </div>
    </div>
  );
}
